
  /* Datos de la Biblia comprimidos. Se descomprimen al cargar la página. */
  window.BIBLE_FULL = undefined;
  (function() {
    const B64GZ = "";

    /* Decodifica base64 a Uint8Array */
    function b64ToBytes(b64) {
      const bin = atob(b64);
      const len = bin.length;
      const bytes = new Uint8Array(len);
      for (let i = 0; i < len; i++) bytes[i] = bin.charCodeAt(i);
      return bytes;
    }

    /* Descomprime gzip usando la API nativa del navegador */
    async function decompressGzip(bytes) {
      const ds = new DecompressionStream('gzip');
      const stream = new Blob([bytes]).stream().pipeThrough(ds);
      const buf = await new Response(stream).arrayBuffer();
      return new TextDecoder('utf-8').decode(buf);
    }

    /* Convierte formato compacto {key:[txt,...]} a {key:[{n,t},...]} */
    function expand(compact) {
      const full = {};
      for (const key in compact) {
        full[key] = compact[key].map((t, i) => ({ n: i + 1, t: t }));
      }
      return full;
    }

    /* Carga síncrona de respaldo con pako no disponible → usar async */
    window.__bibleReady = (async function() {
      try {
        if (typeof DecompressionStream !== 'undefined') {
          const bytes = b64ToBytes(B64GZ);
          const json  = await decompressGzip(bytes);
          window.BIBLE_FULL = expand(JSON.parse(json));
        } else {
          console.error('DecompressionStream no soportado en este navegador.');
          window.BIBLE_FULL = {};
        }
      } catch (e) {
        console.error('Error al descomprimir la Biblia:', e);
        window.BIBLE_FULL = {};
      }
      return window.BIBLE_FULL;
    })();
  })();
  